  ('aboriginal-c5fb3965-moex-00158', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民身分法，原住民與非原住民結婚所生子女，其子女無法依據以下何種方式取得原住民身分？', '["從具原住民身分之父姓", "從具原住民身分之母姓", "取原住民傳統名字", "家中長輩同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00159', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '關於原住民保留地之現行制度，以下敘述何者錯誤？', '["原住民於符合一定資格時得申請無償取得原住民保留地所有權", "原住民因興辦宗教建築設施，得申請無償使用原住民保留地", "原住民保留地制度之母法為山坡地保育利用條例", "原住民取得原住民保留地所有權，得移轉予非原住民身分之配偶"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00160', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族語言發展法之規定，直轄市、縣（市）政府、原住民族地區及原住民人口多少人以上之 非原住民族地區之鄉（鎮、市、區）公所，應置專職原住民族語言推廣人員？', '["500人", "1,000人", "1,500人", "3,000人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00161', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '原住民應先取得原住民族語言能力認證，才能報名參加公務人員特種考試原住民族考試，請問這是那 一個法律的規定？', '["中華民國憲法增修條文", "原住民族基本法", "原住民族語言發展法", "公務人員特種考試原住民族考試規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00162', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民身分法之規定，下列敘述何者錯誤？', '["所謂山地原住民，係指臺灣光復前原籍在山地行政區域內，且戶口調查簿登記其本人或直系血親尊 親屬屬於原住民者", "所謂平地原住民，係指臺灣光復前原籍在平地行政區域內，且戶口調查簿登記其本人或直系血親尊 親屬屬於原住民，並申請戶籍所在地鄉（鎮、市、區）公所登記為平地原住民有案者", "山地原住民與平地原住民身分，任何情形都不可互換", "原住民身分，依法可以拋棄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00163', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據財團法人原住民族語言研究發展基金會設置條例之規定，本基金會之工作人員，除會計相關人員 外，應具備那一種程度以上的原住民族語言能力認證？', '["初級", "中級", "中高級", "高級"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00164', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法，關於原住民申請無償取得原住民保留地所有權土地面積最高限額的 規定，以下敘述何者錯誤？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區，並供農作、養殖 或畜牧使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一點五公頃", "依法得為建築使用之土地，每戶零點一公頃"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00165', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民保留地開發管理辦法第17條，原住民得申請無償取得原住民保留地所有權的資格條件裡， 下列那一項不屬之？', '["原住民依法於原住民保留地設定耕作權、地上權或農育權", "原住民於原住民保留地內有原有自住房屋", "原住民於本辦法施行前使用迄今之原住民保留地", "原住民取得耕作權或地上權登記後繼續自用滿五年者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00166', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民族教育法之規定，中央政府應寬列預算，專款辦理原住民族教育，其比率應為何？', '["不得少於中央統籌分配款預算總額百分之一點九", "不得少於中央教育主管機關預算總額百分之一點九", "不得少於中央原住民族主管機關預算總額百分之一點九", "不得少於中央普通統籌分配款預算總額百分之一點九"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00167', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-110-2d8844e1', 'sub-aboriginal-c5fb3965-01', NULL, 'single_choice', '依據原住民學生升學保障及原住民公費留學辦法規定，原住民學生參加高級中等以上學校新生入學， 依其採計成績加總分百分之十計算，但取得原住民文化及語言能力證明者，以加總分百分之三十五計 算，此規定不適用於以下何者之新生入學？', '["高級中等學校、專科學校五年制", "技術校院四年制、二年制或專科學校二年制", "大學", "研究所"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "f71bb6425250", "answer_pdf_sha1": "5354b6cf864b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "603", "s": "0215", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意與英文", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
